# Category: sql_injection

import psycopg2

def search_users(db_config, username=None, email=None, role=None, status=None):
    conn = None
    try:
        conn = psycopg2.connect(**db_config)
        cur = conn.cursor()

        conditions = []
        params = []

        if username:
            conditions.append("username ILIKE %s")
            params.append(f"%{username}%")
        if email:
            conditions.append("email ILIKE %s")
            params.append(f"%{email}%")
        if role:
            conditions.append("role = %s")
            params.append(role)
        if status:
            conditions.append("account_status = %s")
            params.append(status)

        query = "SELECT id, username, email, role, account_status FROM users"

        if conditions:
            query += " WHERE " + " AND ".join(conditions)

        cur.execute(query, tuple(params))
        users = cur.fetchall()
        cur.close()
        return users
    except (Exception, psycopg2.Error) as error:
        print("Error while connecting to PostgreSQL or executing query:", error)
        return []
    finally:
        if conn:
            conn.close()

